    DEFAULT COLLATE utf8mb4_unicode_ci;

USE it_blog;

-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'BCrypt加密',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '头像URL',
  `bio` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '个性签名',
  `skills` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '技术栈（逗号分隔）',
  `role` tinyint NULL DEFAULT 0 COMMENT '0=普通用户 1=管理员',
  `is_recommended` tinyint NULL DEFAULT 0 COMMENT '0=不推荐 1=推荐作者',
  `status` tinyint NULL DEFAULT 1 COMMENT '0=封禁 1=正常',
  `ban_until` datetime NULL DEFAULT NULL COMMENT '封禁截止时间(NULL=永久)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `username`(`username`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for busi_article
-- ----------------------------
DROP TABLE IF EXISTS `busi_article`;
CREATE TABLE `busi_article`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '鏂囩珷鏍囬?',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '原始Markdown正文',
  `cover_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '封面图URL',
  `author_id` bigint(0) NOT NULL COMMENT '浣滆?ID',
  `category_id` bigint(0) NOT NULL COMMENT '所属分类ID',
  `view_count` int(0) NULL DEFAULT 0 COMMENT '闃呰?閲',
  `like_count` int(0) NULL DEFAULT 0 COMMENT '鐐硅禐閲',
  `comment_count` int(0) NULL DEFAULT 0 COMMENT '璇勮?鏁',
  `status` tinyint(0) NULL DEFAULT 0 COMMENT '0=鑽夌? 1=宸插彂甯',
  `create_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `update_time` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0),
  `summary` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '文章摘要',
  `is_deleted` tinyint(0) NULL DEFAULT 0 COMMENT '软删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_author`(`author_id`) USING BTREE,
  INDEX `idx_category`(`category_id`) USING BTREE,
  INDEX `idx_status_create`(`status`, `create_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '鏂囩珷涓昏〃' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of busi_article
-- ----------------------------
INSERT INTO `busi_article` VALUES (1, 'Updated', '# UPD', '', 1, 1, 54, 1, 14, 1, '2026-06-22 11:50:44', '2026-06-22 16:52:09', '', 0);
INSERT INTO `busi_article` VALUES (3, 'java', '## cesi ![image](/uploads/images/cbb822c3-f3c7-4952-b8e5-286eac690ac5.png)', 'https://lf3-starry.byteimg.com/obj/starry/image/9kwkejo90a_1.webp', 1, 16, 3, 1, 0, 1, '2026-06-22 13:44:07', '2026-06-22 17:03:44', '', 1);
INSERT INTO `busi_article` VALUES (4, 'Test Draft', '# Draft content', '', 1, 1, 0, 0, 0, 0, '2026-06-22 13:47:26', '2026-06-22 16:52:09', '', 0);
INSERT INTO `busi_article` VALUES (10, 'Spring Boot 3 快速入门指南', '# Spring Boot 3 快速入门\n\nSpring Boot 是快速开发脚手架。\n\n```java\n@SpringBootApplication\npublic class DemoApplication { }\n```', '', 1, 6, 128, 15, 2, 1, '2026-06-22 15:51:23', '2026-06-22 16:52:09', '面向初学者的 Spring Boot 3 入门', 0);
INSERT INTO `busi_article` VALUES (11, 'MySQL 索引优化实践', '# MySQL 索引优化\n\n良好的索引设计可以大幅提升查询性能。\n\n常见优化策略：最左前缀原则、覆盖索引、避免索引失效。\n\n```sql\nEXPLAIN SELECT * FROM users WHERE username = admin;\n```', '', 12, 3, 86, 10, 1, 1, '2026-06-22 15:51:48', '2026-06-22 17:03:44', '记录一次 MySQL 索引优化的实际经验', 0);
INSERT INTO `busi_article` VALUES (12, 'Docker 容器化部署', '# Docker 部署指南\n\n使用 Docker 可以快速部署应用，告别环境不一致的烦恼。\n\n```dockerfile\nFROM openjdk:17\nCOPY target/app.jar app.jar\nENTRYPOINT [java, -jar, /app.jar]\n```\n\nDocker Compose 可以编排多容器应用。', '', 13, 4, 196, 22, 2, 1, '2026-06-22 15:51:52', '2026-06-22 17:03:44', '从零开始学习 Docker 容器化部署', 0);
INSERT INTO `busi_article` VALUES (13, 'Vue 3 Composition API 实战', '# Vue 3 Composition API 实战\n\nComposition API 的核心是 setup 函数。\n\n## 基本用法\n```vue\n<script setup>\nimport { ref } from \'vue\'\nconst count = ref(0)\n</script>\n```\n\n让逻辑复用变得更简单。', '', 1, 1, 256, 28, 2, 1, '2026-06-22 15:52:19', '2026-06-22 16:53:06', '分享 Vue 3 Composition API 的实用技巧', 0);
INSERT INTO `busi_article` VALUES (14, 'Python 数据分析入门', '# Python 数据分析入门\n\n## Pandas 基础\n```python\nimport pandas as pd\ndf = pd.read_csv(\'data.csv\')\nprint(df.head())\n```\n\nPandas 是数据分析的核心工具。', '', 12, 9, 198, 20, 0, 1, '2026-06-22 15:52:19', '2026-06-22 17:03:44', 'Python Pandas 数据分析入门教程', 0);
INSERT INTO `busi_article` VALUES (15, 'Spring Boot 3 快速入门指南', '# Spring Boot 3 快速入门\n\nSpring Boot 是 Java 生态中最流行的快速开发框架。\n\n## 核心特性\n- 自动配置：根据依赖自动配置 Bean\n- 起步依赖：一站式引入常用组件\n- 内嵌服务器：无需部署 Tomcat\n\n## 快速开始\n```java\n@SpringBootApplication\npublic class DemoApplication {\n    public static void main(String[] args) {\n        SpringApplication.run(DemoApplication.class, args);\n    }\n}\n```\n\n只需一个注解即可启动应用。', 'https://picsum.photos/seed/spring/800/400', 1, 6, 128, 15, 2, 1, '2026-06-22 16:53:06', '2026-06-22 16:53:06', '面向初学者的 Spring Boot 3 入门教程，涵盖核心特性和快速上手', 0);
INSERT INTO `busi_article` VALUES (16, 'Vue 3 Composition API 实战技巧', '# Vue 3 Composition API 实战\n\nComposition API 是 Vue 3 最重要的新特性。\n\n## setup 语法糖\n```vue\n<script setup>\nimport { ref, computed } from \'vue\'\nconst count = ref(0)\nconst double = computed(() => count.value * 2)\n</script>\n```\n\n## 优势\n- 更好的逻辑复用\n- 更清晰的代码组织\n- 完整的 TypeScript 支持', 'https://picsum.photos/seed/vue/800/400', 1, 1, 256, 28, 2, 0, '2026-06-22 16:53:06', '2026-06-23 11:19:22', '分享 Vue 3 Composition API 的实用技巧和最佳实践', 0);
INSERT INTO `busi_article` VALUES (17, 'MySQL 索引优化实践', '# MySQL 索引优化实践\n\n良好的索引设计可以大幅提升查询性能。\n\n## 常见优化策略\n1. 最左前缀原则\n2. 覆盖索引减少回表\n3. 避免在索引列上使用函数\n\n## 使用 EXPLAIN 分析\n```sql\nEXPLAIN SELECT * FROM users WHERE username = \'admin\';\n```\n\n通过执行计划判断索引是否生效。', 'https://picsum.photos/seed/mysql/800/400', 12, 3, 86, 10, 1, 1, '2026-06-22 16:53:06', '2026-06-22 17:03:44', '记录一次 MySQL 索引优化的实际经验，含 EXPLAIN 分析技巧', 0);
INSERT INTO `busi_article` VALUES (18, 'Docker 容器化部署全流程', '# Docker 容器化部署\n\n使用 Docker 可以告别\"在我机器上能跑\"的问题。\n\n## Dockerfile 示例\n```dockerfile\nFROM openjdk:17\nCOPY target/app.jar app.jar\nENTRYPOINT [\"java\", \"-jar\", \"/app.jar\"]\n```\n\n## Docker Compose\n```yaml\nversion: \"3\"\nservices:\n  app:\n    build: .\n    ports:\n      - \"8080:8080\"\n```', 'https://picsum.photos/seed/docker/800/400', 13, 4, 195, 22, 2, 1, '2026-06-22 16:53:06', '2026-06-22 17:03:44', '从零开始学习 Docker 容器化部署的完整流程', 0);
INSERT INTO `busi_article` VALUES (19, 'Python 数据分析入门', '# Python 数据分析入门\n\nPandas 是 Python 数据分析的核心库。\n\n## 基本操作\n```python\nimport pandas as pd\ndf = pd.read_csv(\"data.csv\")\nprint(df.describe())\n```\n\n## 数据可视化\n```python\nimport matplotlib.pyplot as plt\ndf.plot(kind=\"bar\")\nplt.show()\n```', 'https://picsum.photos/seed/python/800/400', 12, 9, 198, 20, 0, 1, '2026-06-22 16:53:06', '2026-06-22 17:03:44', 'Python Pandas 数据分析入门教程，面向数据科学初学者', 0);

